const items = $input.all();

function cleanText(v) {
  return (v || '').toString().replace(/\s+/g, ' ').trim();
}

function extractField(text, fieldName) {
  const regex = new RegExp(`${fieldName}\\s*:\\s*([^|]+)`, 'i');
  const match = text.match(regex);
  return match ? cleanText(match[1]) : null;
}

function detectActionType(purpose) {
  const p = (purpose || '').toUpperCase();
  if (p.includes('INTERIM DIVIDEND') || p.includes('DIVIDEND')) return 'dividend';
  if (p.includes('BONUS')) return 'bonus';
  if (p.includes('SPLIT')) return 'split';
  if (p.includes('RIGHTS')) return 'rights';
  if (p.includes('BUYBACK')) return 'buyback';
  if (p.includes('MERGER')) return 'merger';
  if (p.includes('DEMERGER')) return 'demerger';
  return 'other';
}

function extractDividendPerShare(purpose) {
  if (!purpose) return null;
  const match = purpose.match(/(?:RS|RE)\s*\.?\s*([0-9]+(?:\.[0-9]+)?)/i);
  return match ? Number(match[1]) : null;
}

function extractRatio(purpose) {
  if (!purpose) return { ratio_text: null, ratio_num: null, ratio_den: null };
  const match = purpose.match(/(\d+)\s*:\s*(\d+)/);
  if (!match) return { ratio_text: null, ratio_num: null, ratio_den: null };

  return {
    ratio_text: `${match[1]}:${match[2]}`,
    ratio_num: Number(match[1]),
    ratio_den: Number(match[2]),
  };
}

const rssItems = items.map(({ json: row }) => {
  const title = cleanText(row.title);
  const content = cleanText(row.content || row.contentSnippet || '');
  const link = cleanText(row.link);
  const pubDate = cleanText(row.pubDate);
  const isoDate = cleanText(row.isoDate);

  const titleMatch = title.match(/^(.*?)\s*-\s*Ex-Date:\s*(.*)$/i);
  const company_name = titleMatch ? cleanText(titleMatch[1]) : title;
  const ex_date = titleMatch ? cleanText(titleMatch[2]) : null;

  const purpose = extractField(content, 'PURPOSE');
  const face_value = extractField(content, 'FACE VALUE');
  const record_date = extractField(content, 'RECORD DATE');
  const series = extractField(content, 'SERIES');
  const action_type = detectActionType(purpose);
  const dividend_per_share = extractDividendPerShare(purpose);
  const ratio = extractRatio(purpose);

  return {
    source: 'nse_rss',
    source_priority: 100,
    source_url: link,
    company_name,
    raw_title: title,
    raw_content: content,
    pubDate,
    isoDate,
    ex_date,
    record_date,
    face_value: face_value ? Number(face_value) || face_value : null,
    series,
    raw_purpose: purpose,
    action_type,
    dividend_per_share,
    ratio_text: ratio.ratio_text,
    ratio_num: ratio.ratio_num,
    ratio_den: ratio.ratio_den,
  };
});

return [
  {
    json: {
      rssItems,
      rss_count: rssItems.length
    }
  }
];

const config = $('Config (Edit Fields)').first().json || {};
const rssItems = $('Normalize RSS').first().json.rssItems || [];
const holdings = $input.all().map(x => x.json);

function normalizeName(name) {
  return (name || '')
    .toString()
    .toLowerCase()
    .replace(/limited/g, '')
    .replace(/\bltd\b/g, '')
    .replace(/company/g, '')
    .replace(/corporation/g, '')
    .replace(/industries/g, 'industry')
    .replace(/[^a-z0-9]/g, '')
    .trim();
}

const configuredClientId = (config.client_id || '').toString().trim();

const filteredHoldings = configuredClientId
  ? holdings.filter(h => (h.client_id || '').toString().trim() === configuredClientId)
  : holdings;

const matches = [];
const seen = new Set();

for (const holding of filteredHoldings) {
  const holdingName = normalizeName(holding.asset_name || holding.company_name || '');

  for (const rss of rssItems) {
    const rssName = normalizeName(rss.company_name || '');
    const isMatch = holdingName && rssName && holdingName === rssName;

    if (!isMatch) continue;

    const dedupeKey = [
      holding.client_id || '',
      holding.symbol || '',
      rss.company_name || '',
      rss.action_type || '',
      rss.record_date || '',
      rss.ex_date || ''
    ].join('|');

    if (seen.has(dedupeKey)) continue;
    seen.add(dedupeKey);

    matches.push({
      client_id: holding.client_id || null,
      client_name: holding.client_name || null,
      email: holding.email || null,
      holding_symbol: holding.symbol || null,
      holding_company_name: holding.asset_name || holding.company_name || null,
      quantity: Number(holding.quantity) || 0,
      avg_buy_price: Number(holding.avg_buy_price) || 0,
      asset_type: holding.asset_type || null,
      ...rss
    });
  }
}

const first = filteredHoldings[0] || {};

const prompt = `
You are a financial corporate action assistant.

STRICT OUTPUT RULES:
- Return ONLY valid JSON
- DO NOT use markdown
- DO NOT wrap response in backticks
- DO NOT add explanations before or after JSON
- Response must start with { and end with }
- Use only the provided data
- Do not invent missing values

Calculation rules:
- For dividend: estimated_cash_benefit = holding_quantity × dividend_per_share
- For bonus: estimated_new_shares = floor(holding_quantity × ratio_num / ratio_den) when ratio is available
- For split: explain the likely unit impact in simple words; set estimated_new_shares to 0 unless clearly derivable
- For rights: if details are incomplete, set needs_review = true
- For merger/demerger/buyback/other with incomplete details: set needs_review = true

Return JSON in exactly this structure:
{
  "client_id": "string",
  "client_name": "string",
  "email": "string|null",
  "total_matches": 0,
  "actions": [
    {
      "company_name": "string",
      "action_type": "string",
      "holding_quantity": 0,
      "estimated_cash_benefit": 0,
      "estimated_new_shares": 0,
      "action_needed": "string",
      "summary": "string",
      "needs_review": false
    }
  ],
  "overall_summary": "string"
}

Input data:
${JSON.stringify(matches, null, 2)}
`;

return [
  {
    json: {
      has_matches: matches.length > 0,
      configured_client_id: configuredClientId || null,
      client_id: first.client_id || configuredClientId || 'CLIENT_001',
      client_name: first.client_name || 'Sample Client',
      email: first.email || 'user@example.com',
      rss_count: rssItems.length,
      holdings_count: filteredHoldings.length,
      total_matches: matches.length,
      matches,
      prompt
    }
  }
];

const item = $input.first().json;

let raw = '';

if (typeof item.content?.parts?.[0]?.text === 'string') {
  raw = item.content.parts[0].text;
} else if (typeof item.parts?.[0]?.text === 'string') {
  raw = item.parts[0].text;
} else if (typeof item.text === 'string') {
  raw = item.text;
} else if (typeof item.content === 'string') {
  raw = item.content;
} else if (typeof item.output === 'string') {
  raw = item.output;
} else if (typeof item.response === 'string') {
  raw = item.response;
} else if (typeof item.message?.content === 'string') {
  raw = item.message.content;
} else if (typeof item.candidates?.[0]?.content?.parts?.[0]?.text === 'string') {
  raw = item.candidates[0].content.parts[0].text;
}

let cleaned = raw;

if (typeof cleaned === 'string') {
  cleaned = cleaned.trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
}

if (!cleaned) {
  return [{ json: { parse_error: true, error_message: 'No JSON text found in model output', raw_ai_output: item } }];
}

try {
  const parsed = JSON.parse(cleaned);
  return [{ json: { ...parsed, parse_error: false } }];
} catch (e) {
  return [{
    json: {
      parse_error: true,
      error_message: e instanceof Error ? e.message : String(e),
      raw_ai_output: raw,
      cleaned_output: cleaned
    }
  }];
}

const data = $json;
const actions = Array.isArray(data.actions) ? data.actions : [];

const subject = `Corporate Actions Summary - ${data.client_name}`;

const actionLines = actions.map((action, index) => {
  return `${index + 1}. ${action.company_name}
- Action Type: ${action.action_type}
- Holding Quantity: ${action.holding_quantity}
- Estimated Cash Benefit: Rs ${action.estimated_cash_benefit}
- Estimated New Shares: ${action.estimated_new_shares}
- Action Needed: ${action.action_needed}
- Summary: ${action.summary}`;
}).join('\n\n');

const body = `Dear ${data.client_name},

Please find below the latest corporate actions matched to your portfolio.

Total Matched Actions: ${data.total_matches}

Overall Summary:
${data.overall_summary}

Detailed Breakdown:
${actionLines}

This is an automated portfolio update based on currently matched corporate action announcements.

Regards,
Portfolio Assistant`;

return [{
  json: {
    client_id: data.client_id,
    client_name: data.client_name,
    email: data.email,
    total_matches: data.total_matches,
    overall_summary: data.overall_summary,
    actions_json: JSON.stringify(actions),
    status: 'matched_actions_sent',
    subject,
    body,
    logged_at: new Date().toISOString()
  }
}];

const input = $json;

return [{
  json: {
    logged_at: new Date().toISOString(),
    client_id: input.client_id,
    client_name: input.client_name,
    email: input.email,
    status: 'no_matching_actions',
    total_matches: 0,
    overall_summary: 'No matching corporate actions were found for this client in the latest NSE RSS run.',
    actions_json: '[]',
    subject: `Corporate Actions Check - ${input.client_name}`,
    body: `Dear ${input.client_name},

We checked the latest NSE corporate action RSS feed and found no matching actions for your current portfolio in this run.

Regards,
Portfolio Assistant`
  }
}];

const item = $('Clean + Parse AI Output').first().json;
const base = $('Compare Holdings + Build Prompt').first().json;
const config = $('Config (Edit Fields)').first().json || {};

return [{
  json: {
    logged_at: new Date().toISOString(),
    client_id: base.client_id,
    client_name: base.client_name,
    email: base.email,
    admin_email: config.admin_email || 'admin@example.com',
    status: 'ai_parse_error',
    total_matches: base.total_matches,
    overall_summary: 'AI returned an invalid response and needs review.',
    actions_json: '[]',
    subject: `Corporate Actions Review Needed - ${base.client_name}`,
    body: `Dear Admin,

The workflow found matching corporate actions for ${base.client_name}, but the AI response could not be parsed.

Error: ${item.error_message || 'Unknown parsing error'}

Please review the run in n8n.`,
    parse_error_details: JSON.stringify(item)
  }
}];
